changeSet.sql:
alter table purchase add column if not exists purchase_kind varchar(20);
alter table purchase add column if not exists source_purchase_id bigint;
update purchase set purchase_kind = 'PURCHASE' where purchase_kind is null;
alter table purchase alter column purchase_kind set default 'PURCHASE';
alter table purchase alter column purchase_kind set not null;

do $$
begin
  if not exists (
    select 1
      from pg_constraint
     where conname = 'fk_purchase__source_purchase_id'
  ) then
    alter table purchase
      add constraint fk_purchase__source_purchase_id
      foreign key (source_purchase_id)
      references purchase(id);
  end if;
end $$;

do $$
begin
  if not exists (
    select 1
      from pg_constraint
     where conname = 'ck_purchase_kind_source_consistency'
  ) then
    alter table purchase
      add constraint ck_purchase_kind_source_consistency
      check (
        (purchase_kind = 'RETURN' and source_purchase_id is not null)
        or
        (purchase_kind = 'PURCHASE' and source_purchase_id is null)
      );
  end if;
end $$;
